#!/usr/bin/env bash
# general-playbook.sh — 通用 Playbook 决策助手 for 公众号写作助手 (微信公众号文章 全链路 — 选题 / 标题 / 开篇 / 结构 / 行文 / 排版 / 配图 / 推送 / 涨粉 / 留言 / 二次传播 / 变现, 单 artifact = 一篇公众号推文).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="公众号写作助手 (微信公众号文章 全链路 — 选题 / 标题 / 开篇 / 结构 / 行文 / 排版 / 配图 / 推送 / 涨粉 / 留言 / 二次传播 / 变现, 单 artifact = 一篇公众号推文)"
TOPIC="通用 Playbook"

usage() {
  cat <<EOF
general-playbook.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 5 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./general-playbook.sh             # interactive
  ./general-playbook.sh --dry-run   # walk through but no file
  ./general-playbook.sh --json      # JSON to stdout
  ./general-playbook.sh --explain   # show backing playbook rules + mental models
  ./general-playbook.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 通用 Playbook 主题下的 playbook 规则组合成交互树。

基于 5 条规则:
  • 如果 头条标题 想 hook → 则 控制 ≤ 30 字 + (数字 OR 反常识 OR 悬念 OR 利益) 之一, 信息流卡片必须前 18-22 字完整露出
  • 如果 一篇头条 完读率 < 40% 且 在看 < 50 → 则 此后 1 周内同题不再发; 进入 A7.4 滑铁卢复盘流程, 找 选题 / 标题 / 钩子 / 时间窗口 / 外部事件 
  • 如果 想做 知识付费 / 训练营 funnel → 则 文章必须 explicit CTA (引导加企微 / 报名页 / 资料包二维码) + 私域 1-3 周培育 + 漏斗 3
  • 如果 AI 写作 输出 直接发文 不手改 + 不标识 → 则 (a) 读者 < 5 篇内识别 (「DeepSeek 味」/「GPT 味」) → 留言 backlash + 取关; (
  • 如果 一篇推文 涉政 / 涉医 / 涉金融 / 涉营销 / AI 生成 / 软广 / 矩阵关联 / 标题党边界 → 则 上线前走《微信公众平台运营规范》8 项自审清单 (标题党 / 配图侵权 / 链接合规 / 二维码诱导 / CTA 话术 

相关心智模型:
  • 「单篇是产品, 账号是公司」 (Account-as-Product): 单篇推文是 product release, 账号是 company; 不为单篇 metric 牺牲账号长期资产 (定位 / voice / 读者画像).
  • 「头部效应是结构性事实, 不是个人努力问题」 (Power-Law Reality): 90% 公众号永远做不到全职收入, 不是「再努力就能突破」, 是流量 / 注意力 / 算法权重的结构性分布; 商业化必须基于此事实设计对冲 (多平台 / 多变现路径), 不卖速成幻想.

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "头条标题 想 hook"
  "一篇头条 完读率 < 40% 且 在看 < 50"
  "想做 知识付费 / 训练营 funnel"
  "AI 写作 输出 直接发文 不手改 + 不标识"
  "一篇推文 涉政 / 涉医 / 涉金融 / 涉营销 / AI 生成 / 软广 / 矩阵关联 / 标题党边界"
)
declare -a RULE_ACTIONS=(
  "控制 ≤ 30 字 + (数字 OR 反常识 OR 悬念 OR 利益) 之一, 信息流卡片必须前 18-22 字完整露出"
  "此后 1 周内同题不再发; 进入 A7.4 滑铁卢复盘流程, 找 选题 / 标题 / 钩子 / 时间窗口 / 外部事件 5 假设之一"
  "文章必须 explicit CTA (引导加企微 / 报名页 / 资料包二维码) + 私域 1-3 周培育 + 漏斗 3 层 (免费 → ¥99-999 入门课 → ¥1999-29999 高客单课); 软引导转化几乎为零"
  "(a) 读者 < 5 篇内识别 (「DeepSeek 味」/「GPT 味」) → 留言 backlash + 取关; (b) 2025-09-01 起《人工智能生成合成内容标识办法》强制标识, 不标 = 违规 + 平台限能力"
  "上线前走《微信公众平台运营规范》8 项自审清单 (标题党 / 配图侵权 / 链接合规 / 二维码诱导 / CTA 话术 / 涉政涉黄涉医 / 软广「广告」标识 / AI 标识); 不走的概率 = 限流 / 删稿 / 失原创权 / 严重封号"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "general-playbook-decision"
fi
